from typing import Dict
from lxml import etree

def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    parser = etree.XMLParser(resolve_entities=False, no_network=True)
    try:
        root = etree.fromstring(xml_data, parser=parser)
    except etree.XMLSyntaxError:
        return None

    query = "//student[username/text() = $username and password/text() = $password]"
    matches = root.xpath(query, username=username, password=password)

    if not matches:
        return None

def get_url_for_query(api_url: str, user_id: str) -> str | None:
    if not user_id:
        return None
    # Validate to prevent path traversal and URL injection
    if not all(c.isalnum() or c in '-_' for c in user_id):
        return None
    return f"{api_url.rstrip('/')}/{user_id}"

